// ============================================================================
// miles-jira-event-router · Build Messages
// ----------------------------------------------------------------------------
// Router de notificaciones de eventos de Jira -> Slack.
// Contrato de entrada (Jira Automation web request):
//   { event_type, board, triggeredAt,
//     pwi: { issueKey, summary, status, area, issueUrl, intakeType, discussionThread } }
//
// event_types soportados (solo pwi_*):
//   pwi_sent_to_dev          -> 2 mensajes: leadership (general) + hilo/area
//   pwi_ready_for_dev        -> 1 mensaje: hilo/area
//   pwi_in_development       -> 1 mensaje: hilo/area
//   pwi_promoted_to_done     -> 1 mensaje: hilo/area
//   pwi_promoted_to_deprecated -> 1 mensaje: hilo/area
//   pwi_promoted_to_blocked  -> 1 mensaje: hilo/area
// Unknown event_types: ignorados silenciosamente.
// ============================================================================

const body = $input.first().json.body || {};
const { event_type, pwi = {} } = body;

// --- Canales fijos ----------------------------------------------------------
const LEADERSHIP_CHANNEL = 'C0ADKPUS83B';   // #4dt-product-technology-delivery

// --- Mapa area -> canal de Slack (fallback cuando no hay discussionThread) ---
const areaToChannel = {
  'Finance & Accounting': 'C0AJ2599DA6',
  'Legal & Compliance':   'C0AJ67HK0ES',
  'Operations':           'C0AK2PW5BGQ',
  'Sales & Partnerships': 'C0AKNPCNNSU',
  'Trading Desk':         'C0AJMRFP0TD',
  'Management':           'C0ARDGP8134',
};

// --- Resolver destino "hilo o canal del area" -------------------------------
// Si hay discussionThread (Intake = Discussion) -> postear en el hilo original.
// Si no (Intake = Manual) -> postear al canal del area como mensaje suelto.
function resolveThreadDestination() {
  const dt = pwi.discussionThread || '';
  // URL formato: https://arduasolutions.slack.com/archives/<CHANNEL>/p<TS sin punto>
  const m = dt.match(/archives\/([A-Z0-9]+)\/p(\d+)/i);
  if (m) {
    const channel = m[1];
    const tsRaw = m[2];
    // reinsertar el punto: ultimos 6 digitos son microsegundos
    const thread_ts = tsRaw.slice(0, -6) + '.' + tsRaw.slice(-6);
    return { channel, thread_ts };
  }
  // Fallback: canal del area, sin thread
  const channel = areaToChannel[pwi.area] || null;
  return channel ? { channel, thread_ts: null } : null;
}

const messages = [];
const push = (dest, text) => {
  if (!dest || !dest.channel) return;
  const m = { channel_id: dest.channel, slack_message: text };
  if (dest.thread_ts) m.thread_ts = dest.thread_ts;
  messages.push(m);
};

// --- Builders por tipo ------------------------------------------------------
const title = pwi.summary || '(sin titulo)';
const key   = pwi.issueKey || '';
const url   = pwi.issueUrl || '';
const link  = (url && key) ? `<${url}|${key}>` : (key || '—');

const builders = {
  pwi_sent_to_dev() {
    // a) Leadership — mensaje general
    push({ channel: LEADERSHIP_CHANNEL, thread_ts: null },
      `🚀 *Nuevo requerimiento listo para desarrollo*\n\n` +
      `*${title}*\n` +
      `${link} · Área: ${pwi.area || '—'}\n\n` +
      `Aprobado por Producto y con Épica creada en el tablero de Tecnología. ` +
      `Cualquier consulta sobre el alcance, respondan este mensaje. 🤝`
    );
    // b) Hilo/area — feedback al solicitante
    push(resolveThreadDestination(),
      `🚀 Tu requerimiento *${title}* (${link}) fue aprobado y enviado a desarrollo. ` +
      `Ya tiene una Épica en el tablero de Tecnología.`
    );
  },
  pwi_ready_for_dev() {
    push(resolveThreadDestination(),
      `📝 Tu requerimiento *${title}* (${link}) ya está *listo para desarrollo* — ` +
      `el equipo de Tecnología lo refinó y lo tomará en el próximo ciclo.`
    );
  },
  pwi_in_development() {
    push(resolveThreadDestination(),
      `🛠️ ¡Manos a la obra! Tu requerimiento *${title}* (${link}) entró *en desarrollo*. ` +
      `Te avisamos cuando esté disponible.`
    );
  },
  pwi_promoted_to_done() {
    push(resolveThreadDestination(),
      `🎉 Tu requerimiento *${title}* (${link}) está *completado y disponible* en el sistema. ` +
      `Probalo y ante cualquier duda o feedback, respondé este mensaje. 🤝`
    );
  },
  pwi_promoted_to_deprecated() {
    push(resolveThreadDestination(),
      `🗂️ Tu requerimiento *${title}* (${link}) fue *descartado*. ` +
      `Si necesitás entender el motivo o reabrir la discusión, respondé este mensaje.`
    );
  },
  pwi_promoted_to_blocked() {
    push(resolveThreadDestination(),
      `⛔ Tu requerimiento *${title}* (${link}) quedó *bloqueado*. ` +
      `El equipo está trabajando para destrabarlo; te mantenemos al tanto por acá.`
    );
  },
};

if (builders[event_type]) builders[event_type]();

return messages.map(m => ({ json: m }));
